import React, { useEffect, useMemo, useState } from "react";
import "./App.css";

const bgImages = [
  "https://images.unsplash.com/photo-1504674900247-0877df9cc836?auto=format&fit=crop&w=1400&q=80",
  "https://images.unsplash.com/photo-1513104890138-7c749659a591?auto=format&fit=crop&w=1400&q=80",
  "https://images.unsplash.com/photo-1565299624946-b28f40a0ae38?auto=format&fit=crop&w=1400&q=80",
  "https://images.unsplash.com/photo-1606787366850-de6330128bfc?auto=format&fit=crop&w=1400&q=80"
];

const ratings = {
  Frankie: 4.4,
  Maggie: 4.2,
  Sandwich: 4.3,
  Burger: 4.5,
  Pizza: 4.7,
  Meals: 4.1,
  Parota: 4.0,
  Rice: 4.4,
  Biryani: 4.8
};

const imageMap = {
  "Veg Frankie 🌯": "https://images.unsplash.com/photo-1626700051175-6818013e1d4f?auto=format&fit=crop&w=900&q=80",
  "Egg Frankie 🥚🌯": "https://images.unsplash.com/photo-1626700051175-6818013e1d4f?auto=format&fit=crop&w=900&q=80",
  "Chicken Frankie 🍗🌯": "https://images.unsplash.com/photo-1626700051175-6818013e1d4f?auto=format&fit=crop&w=900&q=80",

  "Veg Maggie 🍜": "https://images.unsplash.com/photo-1612929633738-8fe44f7ec841?auto=format&fit=crop&w=900&q=80",
  "Egg Maggie 🥚🍜": "https://images.unsplash.com/photo-1612929633738-8fe44f7ec841?auto=format&fit=crop&w=900&q=80",
  "Chicken Maggie 🍗🍜": "https://images.unsplash.com/photo-1612929633738-8fe44f7ec841?auto=format&fit=crop&w=900&q=80",

  "Veg Sandwich 🥪": "https://images.unsplash.com/photo-1528735602780-2552fd46c7af?auto=format&fit=crop&w=900&q=80",
  "Egg Sandwich 🥚🥪": "https://images.unsplash.com/photo-1528735602780-2552fd46c7af?auto=format&fit=crop&w=900&q=80",
  "Chicken Sandwich 🍗🥪": "https://images.unsplash.com/photo-1528735602780-2552fd46c7af?auto=format&fit=crop&w=900&q=80",

  "Veg Burger 🍔": "https://images.unsplash.com/photo-1568901346375-23c9450c58cd?auto=format&fit=crop&w=900&q=80",
  "Chicken Burger 🍗🍔": "https://images.unsplash.com/photo-1568901346375-23c9450c58cd?auto=format&fit=crop&w=900&q=80",

  "Veg Pizza 🍕": "https://images.unsplash.com/photo-1513104890138-7c749659a591?auto=format&fit=crop&w=900&q=80",
  "Chicken Pizza 🍗🍕": "https://images.unsplash.com/photo-1513104890138-7c749659a591?auto=format&fit=crop&w=900&q=80",

  "Veg Meals 🍱": "https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=900&q=80",
  "Veg Parota 🫓": "https://images.unsplash.com/photo-1631452180519-c014fe946bc7?auto=format&fit=crop&w=900&q=80",

  "Veg Fried Rice 🍚": "https://images.unsplash.com/photo-1512058564366-18510be2db19?auto=format&fit=crop&w=900&q=80",
  "Egg Fried Rice 🥚🍚": "https://images.unsplash.com/photo-1512058564366-18510be2db19?auto=format&fit=crop&w=900&q=80",
  "Chicken Fried Rice 🍗🍚": "https://images.unsplash.com/photo-1512058564366-18510be2db19?auto=format&fit=crop&w=900&q=80",

  "Veg Biryani 🍛": "https://images.unsplash.com/photo-1633945274405-b6c5e8f4d1a5?auto=format&fit=crop&w=900&q=80",
  "Chicken Biryani 🍗🍛": "https://images.unsplash.com/photo-1633945274405-b6c5e8f4d1a5?auto=format&fit=crop&w=900&q=80"
};

function App() {
  const [foods, setFoods] = useState([]);
  const [orders, setOrders] = useState([]);
  const [cart, setCart] = useState([]);
  const [page, setPage] = useState("menu");
  const [search, setSearch] = useState("");
  const [category, setCategory] = useState("All");
  const [message, setMessage] = useState("");
  const [bgIndex, setBgIndex] = useState(0);

  const [showCheckout, setShowCheckout] = useState(false);
  const [paymentMethod, setPaymentMethod] = useState("UPI");
  const [orderType, setOrderType] = useState("Takeaway");
  const [note, setNote] = useState("");
  const [placingOrder, setPlacingOrder] = useState(false);

  useEffect(() => {
    loadFoods();
    loadOrders();
  }, []);

  useEffect(() => {
    const timer = setInterval(() => {
      setBgIndex((prev) => (prev + 1) % bgImages.length);
    }, 3500);
    return () => clearInterval(timer);
  }, []);

  const loadFoods = async () => {
    const res = await fetch("http://localhost:8080/foods");
    const data = await res.json();
    setFoods(Array.isArray(data) ? data : []);
  };

  const loadOrders = async () => {
    const res = await fetch("http://localhost:8080/orders");
    const data = await res.json();
    setOrders(Array.isArray(data) ? data : []);
  };

  const categories = useMemo(() => ["All", ...new Set(foods.map((f) => f.category))], [foods]);

  const menuItems = useMemo(
    () =>
      foods.map((f) => ({
        ...f,
        rating: ratings[f.category] || 4.3,
        image: imageMap[f.name] || bgImages[0]
      })),
    [foods]
  );

  const filteredFoods = useMemo(
    () =>
      menuItems.filter(
        (f) =>
          (category === "All" || f.category === category) &&
          f.name.toLowerCase().includes(search.toLowerCase())
      ),
    [menuItems, category, search]
  );

  const popularFoods = useMemo(() => {
    const names = [
      "Chicken Biryani 🍗🍛",
      "Veg Pizza 🍕",
      "Chicken Pizza 🍗🍕",
      "Chicken Burger 🍗🍔",
      "Veg Frankie 🌯",
      "Chicken Fried Rice 🍗🍚"
    ];
    return menuItems.filter((f) => names.includes(f.name));
  }, [menuItems]);

  const addToCart = (food) => {
    setMessage("");
    setCart((prev) => {
      const existing = prev.find((x) => x.id === food.id);
      return existing
        ? prev.map((x) => (x.id === food.id ? { ...x, quantity: x.quantity + 1 } : x))
        : [...prev, { ...food, quantity: 1 }];
    });
  };

  const updateQty = (id, delta) => {
    setCart((prev) =>
      prev
        .map((x) => (x.id === id ? { ...x, quantity: Math.max(0, x.quantity + delta) } : x))
        .filter((x) => x.quantity > 0)
    );
  };

  const subtotal = cart.reduce((sum, x) => sum + x.price * x.quantity, 0);
  const handlingFee = cart.length ? 10 : 0;
  const gst = Math.round(subtotal * 0.05);
  const total = subtotal + handlingFee + gst;
  const totalItems = cart.reduce((sum, x) => sum + x.quantity, 0);
  const waitingTime = 10 + totalItems * 3;

  const checkout = async () => {
    if (!cart.length) {
      setMessage("Add items to cart first");
      return;
    }

    setPlacingOrder(true);
    setMessage("");

    try {
      for (const item of cart) {
        await fetch("http://localhost:8080/orders", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            foodName: `${item.name} | ${orderType} | ${paymentMethod}${note ? " | Note: " + note : ""}`,
            quantity: item.quantity,
            totalPrice: item.price * item.quantity,
            status: "Pending"
          })
        });
      }

      setCart([]);
      setShowCheckout(false);
      setNote("");
      setPaymentMethod("UPI");
      setOrderType("Takeaway");
      setMessage(`Order placed successfully. Estimated waiting time: ${waitingTime} mins`);
      await loadOrders();
      setPage("orders");
    } catch (error) {
      setMessage("Could not place the order");
    } finally {
      setPlacingOrder(false);
    }
  };

  const setOrderStatus = async (order, status) => {
    await fetch(`http://localhost:8080/orders/${order.id}`, {
      method: "PUT",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ ...order, status })
    });
    loadOrders();
  };

  const analytics = useMemo(() => {
    const revenue = orders.reduce((sum, o) => sum + (o.totalPrice || 0), 0);
    const counts = {};
    orders.forEach((o) => {
      const cleanName = o.foodName?.split(" | ")[0] || o.foodName;
      counts[cleanName] = (counts[cleanName] || 0) + o.quantity;
    });
    const top = Object.entries(counts).sort((a, b) => b[1] - a[1]).slice(0, 5);
    return {
      revenue,
      totalOrders: orders.length,
      pending: orders.filter((o) => o.status === "Pending").length,
      completed: orders.filter((o) => o.status === "Completed").length,
      top
    };
  }, [orders]);

  return (
    <div className="app-shell">
      <div className="bg-slider" style={{ backgroundImage: `url("${bgImages[bgIndex]}")` }} />

      <header className="hero">
        <span className="tag">Campus Dining Experience</span>
        <h1>College Canteen Restaurant</h1>
        <p>Fresh meals, fast ordering, premium food ordering experience.</p>
      </header>

      <nav className="nav">
        <button className={page === "menu" ? "active" : ""} onClick={() => setPage("menu")}>🍽 Menu</button>
        <button className={page === "orders" ? "active" : ""} onClick={() => setPage("orders")}>🧾 Orders</button>
        <button className={page === "admin" ? "active" : ""} onClick={() => setPage("admin")}>📊 Dashboard</button>
      </nav>

      {page === "menu" && (
        <>
          <section className="toolbar">
            <div className="search">
              <span>🔎</span>
              <input
                placeholder="Search dishes..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
              />
            </div>

            <div className="chips">
              {categories.map((c) => (
                <button
                  key={c}
                  className={category === c ? "chip active-chip" : "chip"}
                  onClick={() => setCategory(c)}
                >
                  {c}
                </button>
              ))}
            </div>
          </section>

          <section className="panel">
            <div className="section-head-row">
              <div>
                <h2>🔥 Popular Picks</h2>
                <p className="muted">Top favorites from the canteen today</p>
              </div>
            </div>

            <div className="popular-grid">
              {popularFoods.map((food) => (
                <div className="popular-card" key={food.id}>
                  <img src={food.image} alt={food.name} />
                  <div>
                    <h3>{food.name}</h3>
                    <p>{food.category}</p>
                    <strong>₹{food.price}</strong>
                  </div>
                </div>
              ))}
            </div>
          </section>

          <section className="layout">
            <div className="panel">
              <div className="section-head-row">
                <div>
                  <h2>🍴 Full Menu</h2>
                  <p className="muted">Add items to cart and continue to checkout</p>
                </div>
              </div>

              <div className="menu-grid">
                {filteredFoods.map((food) => (
                  <div className="card" key={food.id}>
                    <div className="image-wrap">
                      <img src={food.image} alt={food.name} />
                      <span className="badge">{food.category}</span>
                    </div>

                    <div className="card-body">
                      <h3>{food.name}</h3>
                      <div className="rating">
                        <span>★★★★★</span>
                        <small>{food.rating.toFixed(1)}</small>
                      </div>
                      <div className="price-row">
                        <strong>₹{food.price}</strong>
                        <button onClick={() => addToCart(food)}>Add</button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <aside className="panel cart">
              <h2>🛒 Cart</h2>
              {!cart.length ? (
                <p className="muted">No items added yet</p>
              ) : (
                cart.map((x) => (
                  <div className="cart-item" key={x.id}>
                    <div>
                      <strong>{x.name}</strong>
                      <p>₹{x.price} each</p>
                    </div>
                    <div className="qty">
                      <button onClick={() => updateQty(x.id, -1)}>-</button>
                      <span>{x.quantity}</span>
                      <button onClick={() => updateQty(x.id, 1)}>+</button>
                    </div>
                  </div>
                ))
              )}

              <div className="bill-box">
                <div><span>Subtotal</span><strong>₹{subtotal}</strong></div>
                <div><span>Handling Fee</span><strong>₹{handlingFee}</strong></div>
                <div><span>GST</span><strong>₹{gst}</strong></div>
                <div><span>Waiting Time</span><strong>{waitingTime} mins</strong></div>
              </div>

              <div className="total">
                <span>Total</span>
                <strong>₹{total}</strong>
              </div>

              <button className="checkout" onClick={() => setShowCheckout(true)}>
                Proceed to Checkout
              </button>

              {message && <p className="ok">{message}</p>}
            </aside>
          </section>
        </>
      )}

      {page === "orders" && (
        <section className="panel">
          <h2>📦 Orders</h2>
          <p className="muted">Placed orders and current status</p>

          <div className="menu-grid">
            {orders.map((o) => (
              <div className="card simple" key={o.id}>
                <div className="card-body">
                  <h3>{o.foodName}</h3>
                  <p>Quantity: {o.quantity}</p>
                  <p>Total: ₹{o.totalPrice}</p>
                  <p>Status: <strong>{o.status}</strong></p>
                  <div className="status-row">
                    <button onClick={() => setOrderStatus(o, "Pending")}>Pending</button>
                    <button onClick={() => setOrderStatus(o, "Completed")}>Completed</button>
                    <button onClick={() => setOrderStatus(o, "Cancelled")}>Cancelled</button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </section>
      )}

      {page === "admin" && (
        <section className="panel">
          <h2>📊 Admin Dashboard</h2>
          <div className="stats">
            <div className="stat"><span>Total Orders</span><strong>{analytics.totalOrders}</strong></div>
            <div className="stat"><span>Revenue</span><strong>₹{analytics.revenue}</strong></div>
            <div className="stat"><span>Pending</span><strong>{analytics.pending}</strong></div>
            <div className="stat"><span>Completed</span><strong>{analytics.completed}</strong></div>
          </div>

          <div className="top-list">
            <h3>⭐ Top Ordered Items</h3>
            {analytics.top.length ? (
              analytics.top.map(([name, qty]) => (
                <div className="top-row" key={name}>
                  <span>{name}</span>
                  <strong>{qty}</strong>
                </div>
              ))
            ) : (
              <p className="muted">No analytics yet</p>
            )}
          </div>
        </section>
      )}

      {showCheckout && (
        <div className="modal-backdrop" onClick={() => setShowCheckout(false)}>
          <div className="modal-card" onClick={(e) => e.stopPropagation()}>
            <h2>💳 Checkout</h2>
            <p className="muted">Confirm payment method, order type, and final details</p>

            <div className="checkout-grid">
              <div>
                <label>Payment Method</label>
                <select value={paymentMethod} onChange={(e) => setPaymentMethod(e.target.value)}>
                  <option>UPI</option>
                  <option>Cash on Pickup</option>
                  <option>Card</option>
                </select>
              </div>

              <div>
                <label>Order Type</label>
                <select value={orderType} onChange={(e) => setOrderType(e.target.value)}>
                  <option>Takeaway</option>
                  <option>Dine In</option>
                </select>
              </div>
            </div>

            <div className="checkout-note">
              <label>Special Instructions</label>
              <textarea
                rows="3"
                placeholder="Less spicy, extra sauce, no onion..."
                value={note}
                onChange={(e) => setNote(e.target.value)}
              />
            </div>

            <div className="summary-box">
              <div><span>Total Items</span><strong>{totalItems}</strong></div>
              <div><span>Estimated Waiting</span><strong>{waitingTime} mins</strong></div>
              <div><span>Final Amount</span><strong>₹{total}</strong></div>
            </div>

            <div className="payment-methods-row">
              <span className={paymentMethod === "UPI" ? "pay-tag active-pay" : "pay-tag"}>UPI</span>
              <span className={paymentMethod === "Cash on Pickup" ? "pay-tag active-pay" : "pay-tag"}>Cash</span>
              <span className={paymentMethod === "Card" ? "pay-tag active-pay" : "pay-tag"}>Card</span>
            </div>

            <div className="modal-actions">
              <button className="secondary-btn" onClick={() => setShowCheckout(false)}>Cancel</button>
              <button className="checkout" onClick={checkout} disabled={placingOrder}>
                {placingOrder ? "Placing Order..." : "Confirm & Pay"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
